						Summary:   "review-cost-deferred",
						Body:      ReviewCostDeferredEventBody(report.ResultRev, slot.Result.CostUSD, capTracker.Spent(), capTracker.MaxUSD),
						Actor:     in.Assignee,
						Source:    "ddx work",
						CreatedAt: now().UTC(),
					})
