		}
		if shouldSuppressNoProgress(report) {
			retryAfter := now().UTC().Add(SmartRetryCooldown)
			cooldownStatus := noChanges.EventKind
			if cooldownStatus == "" {
				cooldownStatus = report.Status
			}
			cooldownDetail := noChanges.Reason
			if cooldownDetail == "" {
