	case agenttry.NoChangesActionOperatorRequired:
		if err := applyNoChangesOperatorRequired(w.Store, candidate.ID, assignee, noChanges, now().UTC()); err != nil {
			_ = commitOutcome(ctx, w.Store, candidate.ID, func() error {
