if finalizeDurableAuditOrStop(candidate.ID, report) {
	return executeBeadIterationOutcome{Stop: true}, nil

		return executeBeadIterationOutcome{Stop: true}, nil
	}

	// Use the real attempt_id from the report if available.
	finalAttemptID := report.AttemptID
